import{_ as l,o as i,c as e,ak as r,ax as t}from"./chunks/framework.Chu_0La1.js";const b=JSON.parse('{"title":"🖥️ 服务器状态监控","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"help/other/status.md","filePath":"doc/help/other/status.md"}'),s={name:"help/other/status.md"};function o(n,a,h,c,d,p){return i(),e("div",null,[...a[0]||(a[0]=[r('<h1 id="🖥️-服务器状态监控" tabindex="-1">🖥️ 服务器状态监控 <a class="header-anchor" href="#🖥️-服务器状态监控" aria-label="Permalink to “🖥️ 服务器状态监控”">​</a></h1><div class="feature-hero" style="background:linear-gradient(135deg, #4facfe 0%, #00f2fe 100%);"><span class="feature-icon">🖥️</span><h2>系统状态监控</h2><p>实时展示服务器运行状态和 BOT 性能指标</p></div><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to “功能说明”">​</a></h2><div class="info-box"><blockquote><p>🤔 <strong>我也不知道有什么用(？)</strong></p><p>这个功能主要用于展示 BOT 所在服务器的运行状态，对于普通用户来说可能用处不大，但对于 BOT 管理员来说可以了解系统健康状况。</p></blockquote></div><hr><h2 id="监控指标" tabindex="-1">监控指标 <a class="header-anchor" href="#监控指标" aria-label="Permalink to “监控指标”">​</a></h2><div class="metrics-grid"><h3 id="💻-系统信息" tabindex="-1">💻 系统信息 <a class="header-anchor" href="#💻-系统信息" aria-label="Permalink to “💻 系统信息”">​</a></h3><ul><li><strong>CPU 使用率</strong> - 处理器负载情况</li><li><strong>内存使用</strong> - RAM 占用情况</li><li><strong>磁盘空间</strong> - 存储使用情况</li><li><strong>网络状态</strong> - 网络连接状况</li></ul><h3 id="🤖-bot-状态" tabindex="-1">🤖 BOT 状态 <a class="header-anchor" href="#🤖-bot-状态" aria-label="Permalink to “🤖 BOT 状态”">​</a></h3><ul><li><strong>运行时间</strong> - BOT 已运行时长</li><li><strong>响应延迟</strong> - 指令响应速度</li><li><strong>消息处理</strong> - 消息处理统计</li><li><strong>在线状态</strong> - 连接稳定性</li></ul></div><hr><h2 id="查看方式" tabindex="-1">查看方式 <a class="header-anchor" href="#查看方式" aria-label="Permalink to “查看方式”">​</a></h2><div class="usage-box"><h3 id="自动展示" tabindex="-1">自动展示 <a class="header-anchor" href="#自动展示" aria-label="Permalink to “自动展示”">​</a></h3><p>服务器状态会在特定情况下自动展示，例如：</p><ul><li>系统异常时</li><li>管理员查询时</li><li>定时报告（如配置）</li></ul><h3 id="状态卡片" tabindex="-1">状态卡片 <a class="header-anchor" href="#状态卡片" aria-label="Permalink to “状态卡片”">​</a></h3><p>状态信息以卡片形式展示，包含：</p><ul><li>实时数据图表</li><li>历史趋势分析</li><li>异常告警提示</li></ul></div><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to “技术细节”">​</a></h2><div class="info custom-block github-alert"><p class="custom-block-title">监控原理</p><p></p><ul><li>通过系统 API 获取硬件信息</li><li>定期采样和记录性能数据</li><li>异常时自动触发告警</li></ul></div><div class="tip custom-block github-alert"><p class="custom-block-title">适用场景</p><p></p><ul><li>BOT 管理员监控系统健康</li><li>排查性能问题</li></ul></div><ul><li>了解资源使用趋势</li></ul><hr><h2 id="演示截图" tabindex="-1">演示截图 <a class="header-anchor" href="#演示截图" aria-label="Permalink to “演示截图”">​</a></h2><div class="screenshot-container"><img src="'+t+'" alt="服务器状态监控演示"></div><hr><div class="nav-footer"><a href="./group" class="nav-prev">← 上一页：入群/退群提示</a><a href="/help/sakura/" class="nav-next">下一章：SakuraBOT 专项 →</a></div>',20)])])}const f=l(s,[["render",o]]);export{b as __pageData,f as default};
